const QUESTIONS_CISSP_C2 = [
  { id:30301, domain:3, level:2, question:"Which security model enforces confidentiality by preventing subjects from reading data at a higher classification level?", options:["A Clark-Wilson model","B Bell-LaPadula model","C Biba model","D Brewer-Nash model"], correct:1, explanation:"Bell-LaPadula enforces confidentiality with 'no read up' (simple security property) and 'no write down' (star property), preventing subjects from reading above their clearance level." },
  { id:30302, domain:3, level:2, question:"What does the Clark-Wilson integrity model primarily protect against?", options:["A Unauthorized disclosure of classified data","B Replay attacks in network communications","C Denial of service attacks on critical systems","D Unauthorized modification of data by enforcing well-formed transactions"], correct:3, explanation:"Clark-Wilson protects data integrity by requiring all changes go through certified transformation procedures (TPs), ensuring only well-formed transactions occur." },
  { id:30303, domain:3, level:1, question:"Which evaluation criteria provides a common set of requirements for security products recognized internationally?", options:["A Common Criteria (ISO 15408)","B ISO/IEC 27001","C TCSEC (Orange Book)","D FIPS 140-2"], correct:0, explanation:"Common Criteria (ISO/IEC 15408) is an internationally recognized framework allowing security products to be evaluated against defined Protection Profiles and Evaluation Assurance Levels." },
  { id:30304, domain:3, level:2, question:"What is the primary purpose of a Trusted Platform Module (TPM)?", options:["A Encrypting all data on a network segment","B Providing hardware-based cryptographic key storage and platform integrity measurement","C Managing user authentication for enterprise applications","D Generating pseudo-random numbers for session tokens"], correct:1, explanation:"A TPM is a hardware chip that securely stores cryptographic keys and measures platform integrity through hash values, enabling trusted boot and remote attestation." },
  { id:30305, domain:3, level:2, question:"Which type of cipher operates on fixed-size blocks of data, transforming each block using the same key?", options:["A Stream cipher","B Substitution cipher","C Block cipher","D One-time pad"], correct:2, explanation:"Block ciphers (e.g., AES, DES) process fixed-size blocks of plaintext and produce fixed-size ciphertext blocks, using the same key for each block transformation." },
  { id:30306, domain:3, level:2, question:"What is the purpose of cipher block chaining (CBC) mode in block cipher encryption?", options:["A To increase the key size for stronger encryption","B To reduce the computational overhead of block encryption","C To allow parallel processing of all cipher blocks simultaneously","D To XOR each plaintext block with the previous ciphertext block before encryption"], correct:3, explanation:"In CBC mode, each plaintext block is XORed with the preceding ciphertext block before encryption, ensuring identical plaintext blocks produce different ciphertext and providing error propagation." },
  { id:30307, domain:3, level:1, question:"Which cryptographic algorithm is considered asymmetric?", options:["A AES-256","B 3DES","C RSA","D Blowfish"], correct:2, explanation:"RSA is an asymmetric algorithm using a public/private key pair. AES-256, 3DES, and Blowfish are all symmetric algorithms using a single shared secret key." },
  { id:30308, domain:3, level:2, question:"What is the primary security advantage of elliptic curve cryptography (ECC) over RSA?", options:["A ECC is easier to implement in software than RSA","B ECC provides stronger encryption with shorter key lengths","C ECC supports digital signatures but RSA does not","D ECC is not vulnerable to man-in-the-middle attacks"], correct:1, explanation:"ECC provides equivalent security to RSA with significantly shorter key lengths (e.g., 256-bit ECC ≈ 3072-bit RSA), making it more efficient for mobile and constrained devices." },
  { id:30309, domain:3, level:2, question:"Which principle states that a system should have the minimum number of trusted components necessary to enforce security policy?", options:["A Least privilege","B Defense in depth","C Economy of mechanism","D Separation of duties"], correct:2, explanation:"Economy of mechanism (also called simplicity) states that security mechanisms should be as simple as possible, reducing the trusted computing base and minimizing potential vulnerabilities." },
  { id:30310, domain:3, level:2, question:"What does 'open design' mean as a security design principle?", options:["A Security relies on the secrecy of the design and algorithms","B Security does not depend on secrecy of the design; only keys are secret","C The system is accessible to all users without authentication","D Source code is publicly available for peer review"], correct:1, explanation:"Open design principle states that system security should not rely on keeping the design secret (security through obscurity). Only the keys should be kept secret, making algorithms publicly scrutinizable." },
  { id:30311, domain:3, level:2, question:"In the context of security architecture, what is the Trusted Computing Base (TCB)?", options:["A The totality of protection mechanisms within a computer system responsible for enforcing security policy","B The group of security administrators managing the system","C The set of all hardware components in a secure system","D All data classified as sensitive within an organization"], correct:0, explanation:"The TCB is the combination of all hardware, software, and firmware that enforces the security policy of a system. Minimizing the TCB reduces the attack surface and simplifies verification." },
  { id:30312, domain:3, level:1, question:"Which type of malware replicates itself by attaching to legitimate programs and spreads when those programs are executed?", options:["A Rootkit","B Worm","C Trojan horse","D Virus"], correct:3, explanation:"A virus attaches itself to legitimate host programs and requires user action (executing the host program) to spread. Worms spread without user interaction; trojans disguise as legitimate software; rootkits hide their presence." },
  { id:30313, domain:3, level:2, question:"What is the primary difference between a worm and a virus?", options:["A Worms self-replicate across networks without requiring a host file","B Worms encrypt files while viruses delete them","C Viruses target network devices while worms target endpoints","D Worms require administrator privileges while viruses do not"], correct:0, explanation:"Worms are self-contained programs that replicate and spread across networks independently without needing to attach to host files. Viruses require host programs to propagate." },
  { id:30314, domain:3, level:2, question:"Which vulnerability allows an attacker to execute arbitrary commands by manipulating input that is passed to a system shell?", options:["A SQL injection","B Command injection","C Cross-site scripting","D Directory traversal"], correct:1, explanation:"Command injection occurs when user-supplied input is passed unsanitized to a system shell or interpreter, allowing attackers to execute arbitrary OS commands with the application's privileges." },
  { id:30315, domain:3, level:2, question:"What is a race condition vulnerability in software?", options:["A Software that runs slower than expected under load","B A flaw where system behavior depends on the timing of uncontrollable events","C An error caused by exceeding memory allocation limits","D A condition where two processes compete for limited CPU cycles"], correct:1, explanation:"Race conditions occur when system behavior depends on the sequence or timing of events (e.g., two processes accessing shared data simultaneously), potentially leading to security exploits like TOCTOU attacks." },
  { id:30316, domain:4, level:2, question:"Which OSI layer is responsible for end-to-end communication and error recovery between hosts?", options:["A Data Link layer (Layer 2)","B Network layer (Layer 3)","C Session layer (Layer 5)","D Transport layer (Layer 4)"], correct:3, explanation:"The Transport layer (Layer 4) provides end-to-end communication services, error recovery, flow control, and multiplexing. TCP and UDP operate at this layer." },
  { id:30317, domain:4, level:1, question:"What is the primary purpose of Network Address Translation (NAT)?", options:["A To encrypt traffic between internal and external networks","B To route packets between different network segments","C To map private IP addresses to public IP addresses for internet communication","D To authenticate users before granting network access"], correct:2, explanation:"NAT allows multiple devices with private IP addresses to share a single public IP address, conserving public IP space and providing a degree of network address obscuration." },
  { id:30318, domain:4, level:2, question:"Which protocol provides authentication and encryption for IP packets at the network layer?", options:["A HTTPS","B SSL/TLS","C IPSec","D SSH"], correct:2, explanation:"IPSec operates at the Network layer (Layer 3) and provides authentication (AH header) and encryption (ESP header) for IP packets, securing communication at the network level." },
  { id:30319, domain:4, level:2, question:"In IPSec, what is the difference between Transport mode and Tunnel mode?", options:["A Transport mode encrypts only the payload; Tunnel mode encapsulates the entire original IP packet","B Transport mode is used for host-to-host; Tunnel mode is only for site-to-site VPNs","C Transport mode encrypts the entire IP packet; Tunnel mode encrypts only the payload","D Transport mode uses AH; Tunnel mode uses ESP"], correct:0, explanation:"In Transport mode, only the IP payload is protected; the original IP header remains intact. In Tunnel mode, the entire original IP packet is encapsulated within a new IP packet with a new header, commonly used for VPNs." },
  { id:30320, domain:4, level:2, question:"Which wireless security protocol uses the CCMP encryption mode based on AES?", options:["A WPA (TKIP)","B WPA2/WPA3","C WEP","D WPS"], correct:1, explanation:"WPA2 (and WPA3) use CCMP (Counter Mode with CBC-MAC Protocol), which is based on AES-128, providing strong encryption and integrity protection. WPA uses TKIP; WEP uses RC4." },
  { id:30321, domain:4, level:1, question:"What type of attack involves intercepting and modifying communications between two parties without their knowledge?", options:["A Man-in-the-middle attack","B Session hijacking","C Denial of service attack","D Replay attack"], correct:0, explanation:"A man-in-the-middle (MITM) attack occurs when an attacker secretly intercepts and potentially alters communication between two parties, who believe they are communicating directly with each other." },
  { id:30322, domain:4, level:2, question:"What is the primary function of a proxy firewall (application layer gateway)?", options:["A Filtering packets based solely on source and destination IP addresses","B Terminating and re-establishing connections while inspecting application layer data","C Providing stateful inspection of TCP session state","D Encrypting all traffic passing through the network perimeter"], correct:1, explanation:"Proxy firewalls (application layer gateways) terminate client connections, inspect application-layer content, and create new connections to the destination, providing deep content inspection and hiding internal network topology." },
  { id:30323, domain:4, level:2, question:"Which network attack exploits the trust relationship between IP addresses by falsifying the source address in packets?", options:["A DNS hijacking","B ARP poisoning","C IP spoofing","D MAC flooding"], correct:2, explanation:"IP spoofing involves crafting packets with forged source IP addresses to impersonate trusted hosts, bypass access controls, or facilitate other attacks while hiding the attacker's true identity." },
  { id:30324, domain:4, level:2, question:"What does 802.1X provide in a network security context?", options:["A Wireless encryption using CCMP/AES","B VLAN configuration and management for network segmentation","C Port-based network access control requiring authentication before granting access","D Quality of service prioritization for network traffic"], correct:2, explanation:"IEEE 802.1X provides port-based Network Access Control (PNAC), requiring devices to authenticate (typically via EAP) through an authentication server before being granted network access." },
  { id:30325, domain:4, level:2, question:"What is a botnet?", options:["A A type of intrusion detection system using agent-based monitoring","B A network of servers providing distributed computing resources","C A collection of compromised computers controlled by an attacker for malicious purposes","D A secure overlay network for anonymous communications"], correct:2, explanation:"A botnet is a network of malware-infected computers (bots/zombies) controlled by a command-and-control server. Attackers use botnets for spam, DDoS attacks, credential theft, and other malicious activities." },
  { id:30326, domain:4, level:1, question:"Which protocol is primarily used to dynamically assign IP addresses to network devices?", options:["A DNS","B ICMP","C ARP","D DHCP"], correct:3, explanation:"Dynamic Host Configuration Protocol (DHCP) automatically assigns IP addresses, subnet masks, default gateways, and other network parameters to devices when they connect to a network." },
  { id:30327, domain:4, level:2, question:"What security weakness does DHCP snooping address?", options:["A ARP spoofing attacks on the local network segment","B Rogue DHCP servers distributing malicious network configuration to clients","C DNS cache poisoning attacks on the network","D MAC address flooding that overwhelms switch tables"], correct:1, explanation:"DHCP snooping is a switch security feature that filters DHCP messages, allowing only trusted DHCP server responses, preventing rogue DHCP servers from distributing incorrect gateway or DNS information to clients." },
  { id:30328, domain:4, level:2, question:"Which attack type exhausts server resources by sending SYN packets without completing the TCP three-way handshake?", options:["A UDP flood attack","B SYN flood attack","C Smurf attack","D Fraggle attack"], correct:1, explanation:"A SYN flood attack sends many TCP SYN packets without completing the handshake, filling the server's connection queue with half-open connections and exhausting resources, causing denial of service." },
  { id:30329, domain:4, level:2, question:"What is the purpose of BGP (Border Gateway Protocol) route filtering?", options:["A To prevent the propagation of invalid or malicious routing information between networks","B To authenticate OSPF adjacencies between routers","C To optimize packet forwarding within a single network","D To encrypt routing information between autonomous systems"], correct:0, explanation:"BGP route filtering controls which routes are accepted from and advertised to neighbors, preventing route hijacking, prefix hijacking, and the propagation of misconfigured or malicious routing information." },
  { id:30330, domain:4, level:2, question:"What does the term 'split tunneling' refer to in VPN configurations?", options:["A Dividing VPN traffic between multiple tunnels for load balancing","B Allowing some traffic to go through the VPN while other traffic routes directly to the internet","C Creating separate encrypted channels for different security classifications","D Splitting the VPN key between two administrators for dual control"], correct:1, explanation:"Split tunneling allows VPN users to send organization-bound traffic through the encrypted VPN tunnel while routing internet-bound traffic directly to the internet, bypassing the VPN, which may reduce security visibility." },
  { id:30331, domain:5, level:1, question:"Which access control model grants access based on the subject's clearance level and the object's classification label?", options:["A Discretionary Access Control (DAC)","B Role-Based Access Control (RBAC)","C Mandatory Access Control (MAC)","D Attribute-Based Access Control (ABAC)"], correct:2, explanation:"Mandatory Access Control (MAC) grants access based on security labels assigned to subjects (clearances) and objects (classifications). The system, not the owner, enforces access decisions based on policy." },
  { id:30332, domain:5, level:1, question:"In Role-Based Access Control (RBAC), permissions are assigned to what primary entity?", options:["A Individual user accounts","B Roles, which are then assigned to users","C Security groups based on department","D Objects based on their sensitivity classification"], correct:1, explanation:"In RBAC, permissions are assigned to roles (job functions), and users are assigned to roles. This simplifies administration since changing permissions for a job function only requires updating the role." },
  { id:30333, domain:5, level:2, question:"What is the primary advantage of Attribute-Based Access Control (ABAC) over traditional RBAC?", options:["A ABAC is the only model compliant with government security regulations","B ABAC is simpler to implement and administer than RBAC","C ABAC eliminates the need for authentication before authorization","D ABAC provides fine-grained access control based on multiple attributes of users, resources, and environment"], correct:3, explanation:"ABAC evaluates multiple attributes (user attributes, resource attributes, environmental conditions) to make access decisions, enabling very granular policies like 'grant access only during business hours from corporate devices.'" },
  { id:30334, domain:5, level:2, question:"What is the purpose of an Identity Provider (IdP) in federated identity management?", options:["A To authenticate users and assert their identity to relying parties via trust relationships","B To store and manage all application user databases","C To encrypt all communications between users and applications","D To provision user accounts in multiple systems simultaneously"], correct:0, explanation:"An Identity Provider authenticates users, maintains their identity information, and provides identity assertions (tokens/claims) to relying party services (Service Providers), enabling Single Sign-On across federated systems." },
  { id:30335, domain:5, level:2, question:"Which authentication protocol is commonly used for web-based Single Sign-On, issuing tokens rather than passwords?", options:["A SAML (Security Assertion Markup Language)","B Kerberos","C RADIUS","D LDAP"], correct:0, explanation:"SAML is an XML-based open standard for exchanging authentication and authorization data between identity providers and service providers, enabling browser-based SSO by passing XML assertions." },
  { id:30336, domain:5, level:2, question:"In Kerberos authentication, what is the primary role of the Ticket Granting Service (TGS)?", options:["A To verify the user's initial identity and issue a Ticket Granting Ticket","B To store the master database of all user credentials and secrets","C To issue service tickets for specific resources after presenting a valid TGT","D To encrypt all network traffic between client and server"], correct:2, explanation:"The TGS issues service tickets for specific services when clients present a valid Ticket Granting Ticket (TGT). The TGT is issued by the Authentication Service (AS) after initial authentication." },
  { id:30337, domain:5, level:2, question:"What is the concept of 'just-in-time' access provisioning in privileged access management?", options:["A Provisioning user accounts immediately upon hire without delay","B Automatically revoking access after a fixed time period regardless of activity","C Scheduling privileged access reviews on a regular calendar basis","D Granting elevated privileges only when needed and automatically removing them after the task"], correct:3, explanation:"Just-in-time access grants privileged access temporarily for specific tasks and automatically revokes it afterward, minimizing the exposure window for privileged accounts and following the principle of least privilege." },
  { id:30338, domain:5, level:2, question:"What does OAuth 2.0 primarily provide?", options:["A Authentication of user identity for web applications","B Digital signature verification for software packages","C Encryption of data transmitted between clients and APIs","D Authorization framework allowing third-party applications to access resources without sharing credentials"], correct:3, explanation:"OAuth 2.0 is an authorization framework that enables applications to obtain limited access to user accounts on another service using access tokens, without exposing user credentials to the third-party application." },
  { id:30339, domain:5, level:2, question:"Which biometric characteristic has the highest uniqueness and is considered among the most reliable for authentication?", options:["A Fingerprint","B Iris pattern","C Voice recognition","D Facial geometry"], correct:1, explanation:"Iris patterns are highly unique (even between identical twins and between left/right eyes), stable over time, and difficult to forge, making iris recognition among the most accurate biometric methods." },
  { id:30340, domain:5, level:2, question:"What does the Crossover Error Rate (CER) measure in biometric systems?", options:["A The maximum number of authentication attempts before lockout","B The percentage of biometric data compromised in a breach","C The rate at which enrolled users lose their biometric credentials over time","D The point where false acceptance rate equals false rejection rate, indicating overall accuracy"], correct:3, explanation:"CER (also called Equal Error Rate or EER) is the point where FAR equals FRR. A lower CER indicates a more accurate biometric system. It is used to compare the accuracy of different biometric technologies." },
  { id:30341, domain:5, level:2, question:"What is the primary security concern with password hash storage using MD5 or SHA-1?", options:["A These algorithms produce hashes that are too short for adequate security","B These algorithms cannot be used with salting to improve security","C These algorithms are fast, making brute-force and rainbow table attacks efficient","D These algorithms produce reversible hashes that reveal the original password"], correct:2, explanation:"MD5 and SHA-1 are fast general-purpose hashes. Their speed makes them unsuitable for passwords because attackers can compute billions of hash attempts per second. Password hashing should use slow functions like bcrypt or Argon2." },
  { id:30342, domain:5, level:2, question:"Which provisioning process ensures that access rights are removed when an employee leaves an organization?", options:["A Privilege escalation review","B Access recertification","C Access certification","D Deprovisioning"], correct:3, explanation:"Deprovisioning is the process of revoking a user's access rights, disabling accounts, and removing privileges when they leave the organization or change roles, preventing unauthorized access after separation." },
  { id:30343, domain:5, level:1, question:"What is the 'something you have' authentication factor?", options:["A A physical token, smart card, or mobile device possessed by the user","B A password or PIN known only to the user","C A biometric characteristic unique to the individual","D A location-based check verifying the user's position"], correct:0, explanation:"'Something you have' is a possession factor—a physical item like a hardware token, smart card, key fob, or mobile authenticator app. Multi-factor authentication combines this with other factor types." },
  { id:30344, domain:5, level:2, question:"What is the primary purpose of Privileged Access Management (PAM) solutions?", options:["A Managing end-user passwords across multiple applications","B Controlling, monitoring, and auditing privileged account usage to minimize insider threat risk","C Providing single sign-on for regular user accounts across enterprise applications","D Automating the provisioning of new user accounts in directory services"], correct:1, explanation:"PAM solutions control access to privileged accounts (admin, root, service accounts), enforce least privilege, record privileged sessions, and provide audit trails to detect and prevent misuse of elevated credentials." },
  { id:30345, domain:5, level:2, question:"What does the concept of 'identity federation' enable?", options:["A Automatic synchronization of passwords between multiple identity stores","B Central storage of all user identities across every connected organization","C Trust relationships between domains allowing users to authenticate once and access resources across boundaries","D Mandatory use of the same authentication protocol across all federated systems"], correct:2, explanation:"Identity federation establishes trust between organizations (or domains) so that authenticated users can access resources in partner organizations without needing separate accounts, based on trusted identity assertions." },
  { id:30346, domain:5, level:2, question:"Which protocol is commonly used for centralized authentication, authorization, and accounting in network access scenarios?", options:["A LDAP","B RADIUS","C OAuth 2.0","D TACACS+"], correct:1, explanation:"RADIUS (Remote Authentication Dial-In User Service) provides centralized AAA services for network access, commonly used for VPN, Wi-Fi, and dial-up authentication. TACACS+ provides similar functionality with additional features for device administration." },
  { id:30347, domain:5, level:2, question:"What is the difference between authentication and authorization?", options:["A Authentication verifies who you are; authorization determines what you are permitted to do","B Authentication determines what you can do; authorization verifies who you are","C Authentication is performed by the client; authorization is performed by the server","D Authentication applies to users; authorization applies only to service accounts"], correct:0, explanation:"Authentication verifies identity (who are you?), while authorization determines access rights (what are you allowed to do?). Both are required for secure access control, but they are distinct processes." },
  { id:30348, domain:5, level:2, question:"What is a directory service's primary function in identity management?", options:["A Providing encrypted storage for user credentials and private keys","B Generating one-time passwords for multi-factor authentication","C Auditing and logging all user access events for compliance reporting","D Storing and providing access to information about network resources and users"], correct:3, explanation:"Directory services (e.g., Active Directory, LDAP) store structured information about network objects (users, groups, computers, resources) and provide query and update capabilities, serving as the foundation for authentication and authorization." },
  { id:30349, domain:5, level:2, question:"What is the purpose of access recertification (access review) campaigns?", options:["A Resetting all user passwords on a scheduled basis for security hygiene","B Auditing failed authentication attempts to detect potential intrusions","C Updating access control policies to reflect new business requirements","D Periodically reviewing and confirming that user access rights remain appropriate and necessary"], correct:3, explanation:"Access recertification involves periodic reviews by managers or data owners to confirm that users' access rights are still appropriate for their current role, removing unnecessary or excessive access to maintain least privilege." },
  { id:30350, domain:5, level:2, question:"Which concept ensures that no single person can complete a sensitive transaction or task without involvement from another person?", options:["A Least privilege","B Need to know","C Separation of duties","D Job rotation"], correct:2, explanation:"Separation of duties (SoD) divides critical tasks between multiple people so that no single individual can misuse access or commit fraud without detection. For example, the person who authorizes payments should not also process them." },
  { id:30351, domain:3, level:2, question:"Which security model is based on the concept of Chinese Wall and prevents conflicts of interest?", options:["A Bell-LaPadula model","B Biba model","C Brewer-Nash (Chinese Wall) model","D Clark-Wilson model"], correct:2, explanation:"The Brewer-Nash model (Chinese Wall) prevents conflicts of interest by restricting access to competing companies' data once a user has accessed one company's data, commonly used in financial and consulting environments." },
  { id:30352, domain:3, level:2, question:"What is the primary purpose of a hardware security module (HSM)?", options:["A Providing a secure network perimeter for server rooms","B Monitoring hardware performance and detecting physical intrusions","C Enforcing hardware-level access controls for server BIOS settings","D Generating, storing, and managing cryptographic keys in tamper-resistant hardware"], correct:3, explanation:"HSMs are dedicated hardware devices that generate, store, and protect cryptographic keys and perform cryptographic operations in a tamper-resistant environment, protecting keys from extraction even by administrators." },
  { id:30353, domain:3, level:2, question:"What is steganography used for in information security?", options:["A Encrypting data using a one-time pad for perfect secrecy","B Authenticating digital messages using asymmetric key pairs","C Compressing data before encryption to improve efficiency","D Hiding secret information within ordinary non-secret data or files"], correct:3, explanation:"Steganography conceals the existence of a message by embedding it within another medium (image, audio, video, text) without visibly altering the carrier, used for covert communication or digital watermarking." },
  { id:30354, domain:3, level:2, question:"What does 'complete mediation' mean as a security design principle?", options:["A Every access request must go through an arbitration process involving multiple parties","B Every access to every object must be checked against the access control policy every time","C Security decisions require input from both the user and the system administrator","D Access controls are mediated by a central policy enforcement point only once per session"], correct:1, explanation:"Complete mediation requires that every access to every object be checked against the access control policy each time, preventing attacks that exploit cached or assumed permissions from a prior authorization check." },
  { id:30355, domain:3, level:2, question:"Which of the following best describes a covert channel?", options:["A A communication channel that violates security policy by transmitting information through unintended means","B A hidden network interface used to bypass firewall rules","C An encrypted communication channel used by insider threat actors","D A stealthy malware command-and-control mechanism using social media"], correct:0, explanation:"A covert channel is a communication path that was not intended for communication and violates security policy. Covert storage channels use storage objects; covert timing channels exploit shared system resources." },
  { id:30356, domain:3, level:2, question:"What is the purpose of key derivation functions (KDFs) like PBKDF2 or bcrypt?", options:["A Deriving cryptographic keys from passwords using intentional computational expense to slow attackers","B Distributing encryption keys securely across distributed systems","C Converting symmetric keys to asymmetric keys for hybrid encryption","D Generating asymmetric key pairs from random seed values"], correct:0, explanation:"KDFs derive cryptographic keys from passwords or passphrases, using salt and iterative hashing to make the derivation computationally expensive, significantly slowing brute-force and dictionary attacks." },
  { id:30357, domain:3, level:2, question:"What does the concept of 'fail secure' (fail safe) mean in system design?", options:["A Systems should automatically recover from failure without human intervention","B Redundant systems ensure no failure can occur during critical operations","C When a system fails, it should default to a secure state denying access","D Security mechanisms remain active even during software updates"], correct:2, explanation:"Fail secure (fail safe) means that when a system fails or encounters an error, it defaults to denying access or taking the most restrictive action, preventing failures from creating security vulnerabilities." },
  { id:30358, domain:3, level:2, question:"Which cryptographic primitive provides both confidentiality and integrity in a single operation?", options:["A RSA encryption","B HMAC","C Diffie-Hellman key exchange","D Authenticated Encryption with Associated Data (AEAD)"], correct:3, explanation:"AEAD modes (like AES-GCM or ChaCha20-Poly1305) provide confidentiality through encryption and authenticity/integrity through authentication tags in a single operation, preventing padding oracle and ciphertext tampering attacks." },
  { id:30359, domain:3, level:2, question:"What is the purpose of a digital signature?", options:["A To provide non-repudiation and integrity verification using the sender's private key","B To authenticate the sender using a shared secret key","C To encrypt data so only the intended recipient can read it","D To create a secure channel for key exchange between parties"], correct:0, explanation:"Digital signatures use the sender's private key to sign data, allowing recipients to verify integrity and non-repudiation (the sender cannot deny signing). The signature is verified using the sender's public key." },
  { id:30360, domain:3, level:2, question:"Which hashing algorithm produces a 256-bit output and is recommended for most security applications?", options:["A MD5","B SHA-1","C SHA-256","D CRC-32"], correct:2, explanation:"SHA-256 (part of the SHA-2 family) produces a 256-bit hash, is computationally secure against collision attacks, and is widely recommended for digital signatures, certificates, and data integrity verification." },
  { id:30361, domain:4, level:2, question:"What type of DNS attack involves poisoning the resolver cache with false records to redirect traffic?", options:["A DNS amplification attack","B DNS zone transfer exploit","C DNS tunneling attack","D DNS cache poisoning (DNS spoofing)"], correct:3, explanation:"DNS cache poisoning injects malicious DNS records into a resolver's cache, causing it to return incorrect IP addresses for domain names, redirecting users to attacker-controlled servers for phishing or malware distribution." },
  { id:30362, domain:4, level:2, question:"What is DNS Security Extensions (DNSSEC) designed to prevent?", options:["A Encrypted DNS queries from being intercepted by ISPs","B DNS cache poisoning by providing cryptographic authentication of DNS responses","C DNS amplification attacks by rate-limiting recursive queries","D Unauthorized zone transfers between DNS servers"], correct:1, explanation:"DNSSEC adds cryptographic signatures to DNS records, allowing resolvers to verify that responses are authentic and unmodified, preventing cache poisoning and man-in-the-middle attacks on DNS resolution." },
  { id:30363, domain:4, level:2, question:"Which network protocol uses both UDP and TCP on port 53?", options:["A HTTP","B DNS","C SMTP","D SNMP"], correct:1, explanation:"DNS uses UDP port 53 for standard queries (faster, lower overhead) and TCP port 53 for responses exceeding 512 bytes and zone transfers, which require reliable transmission." },
  { id:30364, domain:4, level:2, question:"What is the primary risk associated with using Telnet for remote server administration?", options:["A Telnet sessions cannot be terminated gracefully if the connection is lost","B Telnet does not support authentication mechanisms","C Telnet only supports IPv4 and not modern IPv6 networks","D Telnet transmits all data including credentials in cleartext"], correct:3, explanation:"Telnet transmits all data, including usernames and passwords, in plaintext without encryption. SSH should be used instead, as it provides encrypted authentication and session data." },
  { id:30365, domain:4, level:2, question:"What does the principle of network segmentation accomplish for security?", options:["A It limits lateral movement by containing breaches and restricting unnecessary inter-segment traffic","B It eliminates the need for perimeter firewalls in modern network designs","C It prevents all users from accessing the internet directly","D It ensures all traffic is inspected by an application-layer proxy"], correct:0, explanation:"Network segmentation divides networks into smaller segments, limiting the blast radius of a security incident by preventing attackers from freely moving laterally between systems once they compromise one segment." },
  { id:30366, domain:4, level:2, question:"Which technology creates virtual isolated network segments within a shared physical network infrastructure?", options:["A VPN (Virtual Private Network)","B DMZ (Demilitarized Zone)","C VLAN (Virtual Local Area Network)","D SDN (Software-Defined Networking)"], correct:2, explanation:"VLANs create logical network segments on shared physical infrastructure, controlling broadcast domains and implementing network segmentation without requiring separate physical hardware for each network segment." },
  { id:30367, domain:4, level:2, question:"What is the primary purpose of a demilitarized zone (DMZ) in network architecture?", options:["A To isolate administrator workstations from regular user networks","B To host public-facing services in a network segment isolated from both the internet and internal network","C To provide a buffer zone where all traffic is decrypted for inspection","D To segment wireless access points from wired infrastructure"], correct:1, explanation:"A DMZ is a network segment between the internet and the internal network that hosts public-facing servers (web, mail, DNS). It limits exposure so that if a public server is compromised, attackers don't have direct access to the internal network." },
  { id:30368, domain:4, level:2, question:"Which type of IDS/IPS detection method creates a baseline of normal behavior and alerts on deviations?", options:["A Signature-based detection","B Rule-based detection","C Protocol-based detection","D Anomaly-based (behavior-based) detection"], correct:3, explanation:"Anomaly-based detection establishes a baseline of normal network or system behavior and alerts when activity deviates significantly from that baseline, allowing detection of unknown or novel attacks but with higher false positive rates." },
  { id:30369, domain:4, level:2, question:"What is the main limitation of signature-based intrusion detection systems?", options:["A They require dedicated hardware and cannot run as software solutions","B They can only monitor network traffic, not host-based activities","C They cannot detect zero-day attacks or malware without a matching signature","D They generate too many false positives for practical deployment"], correct:2, explanation:"Signature-based IDS/IPS rely on known attack patterns (signatures) and cannot detect novel or zero-day attacks that don't match any existing signature in their database." },
  { id:30370, domain:4, level:2, question:"What is a 'sinkhole' in the context of network security?", options:["A A routing technique that redirects malicious traffic to a controlled destination for analysis","B A network device that absorbs and drops all inbound DDoS traffic","C A honeypot designed to attract and analyze botnet traffic","D A deep packet inspection system monitoring DNS queries"], correct:0, explanation:"DNS/route sinkholing redirects traffic destined for known malicious domains/IPs to a controlled server, preventing malware from reaching command-and-control servers and allowing analysis of infected systems." },
  { id:30371, domain:4, level:2, question:"What protocol does HTTPS use to secure web communications?", options:["A IPSec","B SFTP (Secure File Transfer Protocol)","C SSH (Secure Shell)","D TLS (Transport Layer Security)"], correct:3, explanation:"HTTPS uses TLS (formerly SSL) to encrypt HTTP communications, providing confidentiality, integrity, and server authentication (via certificates) for web traffic." },
  { id:30372, domain:4, level:2, question:"Which TLS component verifies the server's identity to the client?", options:["A The server's digital certificate","B The client hello message","C The cipher suite negotiation","D The session key"], correct:0, explanation:"The server's digital certificate (issued by a trusted Certificate Authority) contains the server's public key and identity information. Clients verify the certificate to authenticate the server before trusting the connection." },
  { id:30373, domain:4, level:2, question:"What is perfect forward secrecy (PFS) in TLS?", options:["A Generating unique session keys so compromising the server's private key doesn't compromise past sessions","B Using the same session key for all connections to improve efficiency","C Ensuring all TLS versions support backward compatibility with older clients","D Encrypting the TLS handshake to prevent traffic analysis"], correct:0, explanation:"PFS (using ephemeral Diffie-Hellman or ECDH key exchange) generates unique session keys for each connection. Even if the server's long-term private key is later compromised, past encrypted sessions cannot be decrypted." },
  { id:30374, domain:4, level:2, question:"Which network security technology monitors and filters web traffic based on content and URL categories?", options:["A Network-based IPS","B Email security gateway","C Next-generation firewall","D Secure Web Gateway (SWG)"], correct:3, explanation:"A Secure Web Gateway provides URL filtering, malware inspection, data loss prevention, and SSL inspection for outbound web traffic, enforcing acceptable use policies and blocking malicious content." },
  { id:30375, domain:4, level:2, question:"What type of attack uses multiple systems to overwhelm a target's resources with traffic?", options:["A Man-in-the-middle attack","B Cross-site request forgery attack","C Distributed Denial of Service (DDoS) attack","D Session hijacking attack"], correct:2, explanation:"DDoS attacks coordinate many compromised systems (botnet) to simultaneously flood a target with traffic or requests, exhausting bandwidth, processing capacity, or connections to render the service unavailable." },
  { id:30376, domain:5, level:2, question:"What is the purpose of a Password Authentication Protocol (PAP) replacement like CHAP?", options:["A To avoid transmitting the actual password over the network by using challenge-response","B To eliminate the need for password-based authentication entirely","C To encrypt all PAP authentication exchanges using TLS","D To allow users to authenticate with multiple passwords for redundancy"], correct:0, explanation:"CHAP (Challenge Handshake Authentication Protocol) uses a challenge-response mechanism where only a hash of the password is transmitted, not the password itself, preventing interception attacks that affect PAP." },
  { id:30377, domain:5, level:2, question:"What is the primary security benefit of using smart cards for authentication?", options:["A Smart cards are cheaper to deploy than password-based systems","B Smart cards provide two-factor authentication combining something you have with something you know","C Smart cards eliminate the need for a PKI infrastructure","D Smart cards cannot be replicated or duplicated under any circumstances"], correct:1, explanation:"Smart cards combine a physical card (something you have) with a PIN (something you know), providing two-factor authentication. The private key never leaves the card, preventing extraction attacks." },
  { id:30378, domain:5, level:2, question:"What does SCIM (System for Cross-domain Identity Management) provide?", options:["A Certificate-based authentication for mobile device management","B Encrypted transmission of identity attributes between identity providers","C Single sign-on capability for cloud-based applications","D Standardized API for automating user provisioning and deprovisioning across multiple systems"], correct:3, explanation:"SCIM is an open standard protocol that automates the exchange of user identity information between identity providers and service providers, standardizing user provisioning/deprovisioning to reduce administrative overhead." },
  { id:30379, domain:5, level:2, question:"Which concept limits the damage from a compromised account by ensuring it has only the minimum permissions needed?", options:["A Principle of least privilege","B Separation of duties","C Mandatory access control","D Defense in depth"], correct:0, explanation:"The principle of least privilege grants accounts, processes, and users only the minimum permissions required for their specific tasks, limiting the blast radius if credentials are compromised." },
  { id:30380, domain:5, level:2, question:"What is the difference between identification and authentication?", options:["A Identification is performed by the server; authentication is performed by the client","B Identification claims an identity; authentication proves that the claimed identity is genuine","C Identification uses passwords; authentication uses biometrics","D Identification is a one-time process; authentication occurs at every login"], correct:1, explanation:"Identification is the act of claiming an identity (e.g., entering a username). Authentication is the process of proving the claimed identity is genuine (e.g., providing a password, token, or biometric)." },
  { id:30381, domain:5, level:2, question:"What is the primary purpose of a centralized identity management system?", options:["A Automatically granting users all permissions needed for their department","B Providing faster authentication by caching credentials locally on each device","C Eliminating the need for access control policies across connected systems","D Managing user identities, access rights, and provisioning from a single authoritative source"], correct:3, explanation:"Centralized identity management provides a single authoritative source for user identities, roles, and access rights, simplifying provisioning/deprovisioning, ensuring consistency, and improving audit capabilities." },
  { id:30382, domain:5, level:2, question:"Which access control type uses rules defined by system administrators and cannot be changed by data owners?", options:["A Discretionary Access Control (DAC)","B Mandatory Access Control (MAC)","C Role-Based Access Control (RBAC)","D Attribute-Based Access Control (ABAC)"], correct:1, explanation:"In MAC, access control policies are set by administrators or the system based on security labels, and individual data owners cannot override these rules. This is commonly used in military/government environments." },
  { id:30383, domain:5, level:2, question:"What is OpenID Connect (OIDC) built on top of?", options:["A SAML 2.0 for identity federation","B Kerberos for distributed authentication","C OAuth 2.0, adding an identity layer for authentication","D LDAP for directory-based identity management"], correct:2, explanation:"OpenID Connect is an authentication layer built on top of OAuth 2.0. It adds an ID token (JWT) that contains user identity information, enabling both authentication and authorization in a single framework." },
  { id:30384, domain:5, level:2, question:"What is a common attack against Kerberos that involves requesting many service tickets to crack offline?", options:["A Pass-the-hash attack","B Golden ticket attack","C Silver ticket attack","D Kerberoasting attack"], correct:3, explanation:"Kerberoasting requests service tickets for SPNs, then attempts to crack them offline. Since service tickets are encrypted with the service account's password hash, weak passwords can be recovered without triggering online authentication failures." },
  { id:30385, domain:5, level:2, question:"What does a 'golden ticket' attack in Kerberos allow an attacker to do?", options:["A Forge authentication cookies for any web application","B Bypass multi-factor authentication for privileged accounts","C Create fake X.509 certificates to impersonate servers","D Forge Kerberos TGTs to impersonate any user, including administrators, by knowing the KRBTGT hash"], correct:3, explanation:"A golden ticket attack forges Ticket Granting Tickets using the compromised KRBTGT account hash, allowing the attacker to impersonate any user in the domain with any group membership, providing persistent domain-wide access." },
  { id:30386, domain:5, level:2, question:"Which authentication method involves verifying a user's identity based on behavioral patterns over time?", options:["A Multi-factor authentication","B Continuous authentication (behavioral biometrics)","C Certificate-based authentication","D Knowledge-based authentication"], correct:1, explanation:"Continuous authentication (behavioral biometrics) monitors patterns like typing cadence, mouse movements, and usage behavior throughout a session to continuously verify user identity, detecting session hijacking or account takeover." },
  { id:30387, domain:5, level:2, question:"What is the primary security issue with shared accounts (generic accounts)?", options:["A Shared accounts prevent individual accountability and complicate audit trails","B Shared accounts are more difficult to manage in Active Directory","C Shared accounts require more complex password policies to maintain","D Shared accounts are incompatible with most modern authentication protocols"], correct:0, explanation:"Shared accounts (e.g., 'admin' used by multiple people) break individual accountability. It's impossible to determine which individual performed specific actions, violating non-repudiation and making forensic investigation difficult." },
  { id:30388, domain:5, level:2, question:"What is a time-based one-time password (TOTP)?", options:["A A password generated from a shared secret and current time, valid only briefly","B A password valid only during business hours to limit unauthorized access","C A password that changes after a fixed number of authentication attempts","D A temporary password sent via SMS that expires after first use"], correct:0, explanation:"TOTP generates authentication codes from a shared secret combined with the current time (typically 30-second windows), producing short-lived codes that are valid only briefly, preventing replay attacks." },
  { id:30389, domain:5, level:2, question:"What is the primary advantage of FIDO2/WebAuthn for authentication?", options:["A It provides phishing-resistant authentication using public key cryptography tied to the origin","B It eliminates the need for any form of user verification","C It is backward compatible with all legacy password-based systems","D It requires only a username without any additional factor"], correct:0, explanation:"FIDO2/WebAuthn uses asymmetric cryptography where the private key never leaves the authenticator and the key is bound to the specific origin, making it resistant to phishing because credentials cannot be reused on fake sites." },
  { id:30390, domain:5, level:2, question:"What is account harvesting in the context of identity attacks?", options:["A Enumerating valid usernames through login error messages or timing differences","B Extracting all user accounts from a compromised directory service","C Collecting user credentials from phishing campaigns over time","D Aggregating identity information from multiple breached databases"], correct:0, explanation:"Account harvesting exploits authentication systems that reveal whether a username exists (through different error messages or response times), allowing attackers to enumerate valid accounts for targeted credential attacks." },
  { id:30391, domain:3, level:2, question:"What is the role of a Certificate Authority (CA) in a PKI?", options:["A To store all private keys for recovery purposes","B To issue, sign, and revoke digital certificates binding identities to public keys","C To encrypt all communications between clients and servers","D To manage access control policies for certificate holders"], correct:1, explanation:"A CA is a trusted third party that issues digital certificates, vouching for the binding between an entity's identity and its public key. The CA signs certificates with its own private key, allowing others to verify authenticity." },
  { id:30392, domain:3, level:2, question:"What is a Certificate Revocation List (CRL)?", options:["A A list of certificates that have been revoked before their expiration date","B A list of certificates pending issuance by a Certificate Authority","C A list of approved certificate algorithms and key lengths","D A database of all certificates issued by a Certificate Authority"], correct:0, explanation:"A CRL is a list published by a CA containing serial numbers of certificates that have been revoked (due to key compromise, personnel changes, etc.) before their scheduled expiration. Applications check CRLs to reject revoked certificates." },
  { id:30393, domain:3, level:2, question:"What advantage does OCSP (Online Certificate Status Protocol) provide over CRL?", options:["A OCSP provides better encryption than CRL-based verification","B OCSP eliminates the need for Certificate Authorities to revoke certificates","C OCSP allows certificates to be verified without network connectivity","D OCSP provides real-time certificate status without downloading large CRL files"], correct:3, explanation:"OCSP allows real-time certificate status checking by querying the CA's OCSP responder, avoiding the overhead of downloading potentially large CRL files and providing more timely revocation status." },
  { id:30394, domain:3, level:2, question:"What is the key escrow concept in cryptography?", options:["A Encrypting backup copies of keys with a secondary key pair","B Storing encryption keys in a physically secure hardware vault","C Temporary transfer of encryption keys to a trusted third party for lawful access","D Splitting keys between multiple administrators using secret sharing"], correct:2, explanation:"Key escrow involves depositing copies of encryption keys with a trusted third party (often a government agency or compliance officer) so that encrypted data can be accessed under lawful authority or for business continuity purposes." },
  { id:30395, domain:3, level:2, question:"What does 'security through obscurity' mean and why is it considered a weak security strategy?", options:["A Using complex encryption algorithms that attackers find difficult to understand","B Relying on secrecy of design or implementation as the primary security mechanism, which fails when secrets are exposed","C Hiding systems behind network address translation to obscure their true addresses","D Limiting public documentation about security controls to prevent enumeration"], correct:1, explanation:"Security through obscurity relies on keeping system design, vulnerabilities, or configurations secret. It is weak because once the secret is discovered (through reverse engineering, leaks, or research), all security disappears. Defense should not depend on obscurity." },
  { id:30396, domain:3, level:2, question:"What is the Diffie-Hellman protocol used for?", options:["A Providing certificate-based authentication in PKI environments","B Encrypting messages using asymmetric public key encryption","C Generating and verifying digital signatures for message authentication","D Securely establishing a shared secret key over an untrusted channel"], correct:3, explanation:"Diffie-Hellman allows two parties to establish a shared secret key over an insecure channel without previously sharing any secret information, by exchanging public values and computing a common secret from their private values." },
  { id:30397, domain:4, level:2, question:"What is 'network access control' (NAC)?", options:["A Controlling user access to specific network resources based on roles","B Filtering network traffic based on application-layer content inspection","C Managing network administrator credentials for device configuration","D Enforcing security policy compliance before granting devices access to the network"], correct:3, explanation:"NAC evaluates endpoint compliance (patches, AV, configuration) before granting network access, quarantining non-compliant devices, ensuring only healthy and policy-compliant devices connect to the network." },
  { id:30398, domain:4, level:2, question:"What is the primary security risk of BYOD (Bring Your Own Device) policies?", options:["A Personal devices are typically slower than corporate devices","B Personal devices may not meet corporate security standards and can introduce vulnerabilities","C BYOD increases helpdesk costs for device support","D Personal devices are incompatible with enterprise authentication protocols"], correct:1, explanation:"BYOD introduces risks including unpatched personal devices, mixing personal and corporate data, difficulty enforcing security policies, and challenges with device management and remote wipe of corporate data." },
  { id:30399, domain:4, level:2, question:"What does a next-generation firewall (NGFW) provide beyond traditional stateful inspection?", options:["A Hardware-accelerated encryption for all network traffic","B Automated vulnerability scanning of connected network devices","C Application awareness, user identity integration, and deep packet inspection capabilities","D Physical port security and MAC address filtering for endpoints"], correct:2, explanation:"NGFWs provide traditional stateful inspection plus application-layer (Layer 7) awareness, user identity integration, SSL/TLS inspection, IPS capabilities, and threat intelligence feeds, enabling policy enforcement based on applications and users." },
  { id:30400, domain:4, level:2, question:"What security mechanism does 802.1AE (MACsec) provide?", options:["A Wireless network encryption for enterprise Wi-Fi deployments","B Encrypted tunneling for site-to-site VPN connections","C Multi-factor authentication for network device access","D Layer 2 encryption and authentication for wired Ethernet frames"], correct:3, explanation:"MACsec (802.1AE) provides hop-by-hop encryption and authentication at Layer 2 (Ethernet), securing traffic between directly connected devices and protecting against eavesdropping and tampering on local network segments." },
  { id:30401, domain:5, level:2, question:"What is an access control matrix?", options:["A A table mapping subjects to objects with associated permissions","B A visual representation of physical access zones in a facility","C A risk scoring system for privilege escalation attempts","D A cryptographic structure for managing certificate hierarchies"], correct:0, explanation:"An access control matrix is a conceptual model representing relationships between subjects (users, processes) and objects (files, resources), with each cell containing the permissions the subject has on the object." },
  { id:30402, domain:5, level:2, question:"What is the security benefit of account lockout policies?", options:["A They prevent brute-force attacks by locking accounts after repeated failed authentication attempts","B They reduce the number of passwords users need to remember","C They enforce password complexity requirements automatically","D They alert administrators when users attempt to log in after hours"], correct:0, explanation:"Account lockout policies lock user accounts after a configurable number of failed login attempts, preventing brute-force and password spraying attacks by limiting how many password guesses an attacker can make." },
  { id:30403, domain:5, level:2, question:"What is the primary purpose of a privileged identity management (PIM) solution?", options:["A Managing regular user account passwords across enterprise applications","B Providing multi-factor authentication for service accounts","C Monitoring network traffic for signs of privileged account compromise","D Governing elevated access rights, including just-in-time provisioning and approval workflows"], correct:3, explanation:"PIM solutions manage and govern privileged accounts through access request workflows, approval processes, time-limited access, session recording, and risk-based policies to enforce least-privilege for elevated access." },
  { id:30404, domain:5, level:2, question:"What type of attack involves stealing a user's session token to impersonate them?", options:["A Session hijacking attack","B Credential stuffing attack","C Privilege escalation attack","D Man-in-the-browser attack"], correct:0, explanation:"Session hijacking steals a valid session token (via XSS, network sniffing, or prediction) to impersonate the authenticated user, bypassing authentication since the server trusts the token." },
  { id:30405, domain:5, level:2, question:"What does 'account correlation' mean in identity governance?", options:["A Comparing account permissions to detect unauthorized privilege escalation","B Linking multiple user accounts belonging to the same individual across different systems","C Synchronizing account policies across all enterprise systems","D Associating user behavior analytics with specific account activities"], correct:1, explanation:"Account correlation links multiple accounts (Active Directory, cloud, application) that belong to the same individual, enabling centralized governance, unified access reviews, and complete visibility of an individual's total access." },
  { id:30406, domain:3, level:2, question:"What is the primary purpose of a security information and event management (SIEM) system?", options:["A Aggregating and correlating security events from multiple sources for centralized monitoring and analysis","B Blocking malicious network traffic at the perimeter","C Encrypting sensitive data stored across enterprise systems","D Managing patch deployment across all endpoints in the environment"], correct:0, explanation:"SIEM systems collect logs and security events from across the environment, correlate them to detect patterns, generate alerts, and support compliance reporting and incident investigation." },
  { id:30407, domain:3, level:2, question:"What does the concept of 'defense in depth' imply for security architecture?", options:["A Using the most expensive security controls available for critical assets","B Implementing multiple layers of security controls so that the failure of one doesn't compromise the whole system","C Focusing all security investment on perimeter defenses to prevent breaches","D Ensuring all security functions are performed by a single integrated platform"], correct:1, explanation:"Defense in depth uses multiple independent security layers (perimeter, network, host, application, data) so that an attacker must defeat several controls, and failure of one layer doesn't mean complete compromise." },
  { id:30408, domain:3, level:2, question:"What is a security baseline in the context of system hardening?", options:["A The initial state of a system before any security controls are applied","B The minimum acceptable security configuration for a particular system type","C A performance benchmark for measuring security tool effectiveness","D The maximum security configuration achievable for a given platform"], correct:1, explanation:"A security baseline defines the minimum required security configuration (e.g., enabled controls, disabled services, patches applied) for a system type, ensuring consistent protection across similar systems in the environment." },
  { id:30409, domain:3, level:2, question:"What is a supply chain attack in software security?", options:["A Compromising a trusted third-party component or vendor to distribute malicious code to downstream targets","B An attack targeting manufacturing facilities to disrupt product delivery","C A social engineering attack targeting employees in procurement roles","D A denial of service attack against logistics and ordering systems"], correct:0, explanation:"Supply chain attacks compromise software dependencies, build systems, update mechanisms, or vendors to inject malicious code that is then distributed to many downstream customers who trust the compromised component." },
  { id:30410, domain:3, level:2, question:"What is the purpose of code signing?", options:["A Encrypting source code to prevent intellectual property theft","B Documenting code authorship for legal liability purposes","C Obfuscating compiled code to prevent reverse engineering","D Verifying software authenticity and integrity using the developer's digital signature"], correct:3, explanation:"Code signing uses the developer's private key to sign software, allowing users to verify that code is from a trusted source and hasn't been tampered with since signing, preventing installation of malicious or modified software." },
  { id:30411, domain:3, level:2, question:"What is a side-channel attack?", options:["A An attack exploiting a secondary communication channel in a protocol implementation","B An attack using social engineering alongside technical exploitation","C An attack targeting backup systems when primary systems are hardened","D An attack deriving secret information from physical implementation characteristics like power consumption or timing"], correct:3, explanation:"Side-channel attacks exploit information leaked through physical implementation (power consumption, electromagnetic emissions, timing, sound) rather than weaknesses in the algorithm itself, circumventing mathematical security guarantees." },
  { id:30412, domain:3, level:2, question:"What does the principle of psychological acceptability require?", options:["A Security training should be designed to be memorable and engaging","B Users should understand and accept the rationale behind security policies","C Security mechanisms should not make resources more difficult to access than without them","D Security awareness programs should address cognitive biases in users"], correct:2, explanation:"Psychological acceptability requires that security mechanisms not create excessive burden, as users will work around controls they find too difficult to use. Usable security leads to better compliance." },
  { id:30413, domain:3, level:2, question:"What is fuzzing in software security testing?", options:["A Obfuscating code to test if reverse engineering tools can analyze it","B Testing security controls under high-load conditions to identify performance issues","C Providing malformed or unexpected inputs to an application to discover vulnerabilities","D Reviewing code logic by simulating the thought process of an attacker"], correct:2, explanation:"Fuzzing (fuzz testing) sends random, malformed, or unexpected inputs to an application to discover crashes, hangs, memory leaks, and security vulnerabilities like buffer overflows or injection flaws that proper input validation would prevent." },
  { id:30414, domain:4, level:2, question:"What is the purpose of out-of-band network management?", options:["A Managing network devices using encrypted in-band protocols","B Monitoring network traffic without impacting production bandwidth","C Using a separate management network isolated from production traffic for device administration","D Providing redundant network paths for critical management traffic"], correct:2, explanation:"Out-of-band management uses a separate, dedicated network for managing infrastructure devices, ensuring administrators can access devices for troubleshooting even when production networks are down or compromised." },
  { id:30415, domain:4, level:2, question:"What is a packet-filtering firewall's primary limitation compared to stateful inspection firewalls?", options:["A Packet filters cannot inspect UDP traffic","B Packet filters are unable to handle high traffic volumes","C Packet filters examine each packet independently without tracking connection state","D Packet filters cannot be configured with deny rules"], correct:2, explanation:"Packet filters evaluate each packet independently against rules but don't track connection state. Stateful firewalls maintain a connection table, allowing them to distinguish valid response packets from unsolicited inbound packets." },
  { id:30416, domain:4, level:2, question:"What does a content delivery network (CDN) provide as a security benefit?", options:["A DDoS mitigation by absorbing and distributing attack traffic across many edge locations","B End-to-end encryption between clients and origin servers","C Vulnerability scanning of web application source code","D Certificate management for all hosted domains automatically"], correct:0, explanation:"CDNs distribute content across many edge nodes globally, which helps absorb DDoS attacks by distributing the attack traffic and providing scrubbing capabilities, protecting origin servers from volumetric attacks." },
  { id:30417, domain:4, level:2, question:"Which protocol is used for sending email and is vulnerable to spoofing without additional authentication controls?", options:["A IMAP","B SMTP","C POP3","D MIME"], correct:1, explanation:"SMTP (Simple Mail Transfer Protocol) lacks built-in sender authentication, making it susceptible to spoofing. SPF, DKIM, and DMARC are additional mechanisms layered on top of SMTP to authenticate senders." },
  { id:30418, domain:4, level:2, question:"What is DMARC and what does it enforce?", options:["A An email authentication framework that specifies how to handle emails failing SPF or DKIM checks","B A network monitoring protocol that reports on traffic anomalies","C A firewall policy standard for filtering malicious email attachments","D A DNS security extension for protecting email server records"], correct:0, explanation:"DMARC (Domain-based Message Authentication, Reporting & Conformance) builds on SPF and DKIM, letting domain owners specify how receiving mail servers should handle emails that fail authentication (none, quarantine, or reject)." },
  { id:30419, domain:4, level:2, question:"What type of malware hides itself by modifying the OS to conceal its presence?", options:["A Spyware","B Adware","C Rootkit","D Ransomware"], correct:2, explanation:"Rootkits modify the operating system kernel or other low-level components to hide their presence from security tools, system administrators, and antivirus software, making detection and removal extremely difficult." },
  { id:30420, domain:4, level:2, question:"What is network traffic analysis (NTA) used for in security monitoring?", options:["A Encrypting all network communications for confidentiality","B Managing network device configurations and firmware updates","C Detecting anomalies and threats by analyzing network flow data and packet content","D Optimizing network bandwidth allocation for critical applications"], correct:2, explanation:"NTA analyzes network flow metadata (NetFlow, IPFIX) and packet data to detect threats like lateral movement, data exfiltration, C2 communications, and other anomalous behaviors that indicate compromise." },
  { id:30421, domain:5, level:2, question:"What is a credential stuffing attack?", options:["A Using stolen username/password pairs from one breach to authenticate to other services","B Brute-forcing passwords by trying all possible combinations","C Injecting malicious credentials into authentication databases","D Social engineering users into revealing their login credentials"], correct:0, explanation:"Credential stuffing uses large lists of username/password combinations from data breaches to attempt login to other services, exploiting password reuse. Multi-factor authentication is the most effective defense." },
  { id:30422, domain:5, level:2, question:"What is the purpose of password salting?", options:["A Adding extra characters to make passwords longer and more complex","B Encrypting stored passwords with a system-wide encryption key","C Adding a unique random value to each password before hashing to prevent rainbow table attacks","D Rotating passwords automatically after a configured time period"], correct:2, explanation:"A salt is a unique random value added to each password before hashing, ensuring that identical passwords produce different hashes, defeating precomputed rainbow tables and making parallel cracking attacks more expensive." },
  { id:30423, domain:5, level:2, question:"What does non-repudiation in information security ensure?", options:["A That a party cannot deny having performed a specific action or sent a specific message","B That all communications are encrypted to prevent eavesdropping","C That system availability is maintained during security incidents","D That access control decisions cannot be appealed by users"], correct:0, explanation:"Non-repudiation ensures that a party cannot deny performing an action (e.g., sending a message, approving a transaction). Digital signatures provide non-repudiation by binding the signer's private key to the signed data." },
  { id:30424, domain:5, level:2, question:"What is the primary purpose of a single sign-on (SSO) system?", options:["A Allowing users to authenticate once and access multiple systems without re-entering credentials","B Requiring users to authenticate separately to each system for maximum security","C Centralizing all user passwords in a single encrypted vault","D Eliminating the need for passwords by using biometric authentication only"], correct:0, explanation:"SSO allows users to authenticate once and seamlessly access multiple connected systems, improving user experience while centralizing authentication, simplifying management, and enabling consistent security policy enforcement." },
  { id:30425, domain:5, level:2, question:"What is the security principle of 'need to know'?", options:["A Users should know their security clearance level and restrictions","B Security teams need complete visibility into all user activities","C Access to information should be limited to those who require it for their specific job function","D Management needs to be informed of all security incidents immediately"], correct:2, explanation:"Need to know limits information access to individuals who require that specific information to perform their job duties, complementing MAC clearance requirements to ensure that cleared individuals only access relevant information." },
  { id:30426, domain:5, level:2, question:"What is an account takeover (ATO) attack?", options:["A An attacker creating new accounts in a target system","B Elevating privileges within a compromised system account","C Gaining unauthorized control of a legitimate user's account through various credential theft techniques","D Transferring account ownership through social engineering of IT administrators"], correct:2, explanation:"Account takeover involves illegitimately gaining access to a user's account using stolen credentials, session tokens, SIM swapping, or other techniques, allowing attackers to impersonate the victim and abuse their access." },
  { id:30427, domain:5, level:2, question:"What does user and entity behavior analytics (UEBA) detect?", options:["A Network intrusions at the perimeter firewall level","B Anomalous user and system behavior that may indicate insider threats or compromised accounts","C Malware signatures in files and email attachments","D Unauthorized software installations on managed endpoints"], correct:1, explanation:"UEBA establishes behavioral baselines for users and entities, then detects deviations that may indicate insider threats, compromised accounts, or data exfiltration attempts, providing context that signature-based tools miss." },
  { id:30428, domain:3, level:2, question:"What does isolation in virtualization security mean?", options:["A Running virtual machines only on dedicated physical hardware","B Separating development and production environments into different hypervisors","C Preventing virtual machines from accessing external networks","D Ensuring that virtual machines cannot directly access each other's memory or resources"], correct:3, explanation:"VM isolation ensures that virtual machines are logically separated, preventing one VM from reading or modifying another VM's memory, storage, or CPU state, even when sharing physical hardware resources." },
  { id:30429, domain:3, level:2, question:"What is a hypervisor's role in virtual machine security?", options:["A Encrypting all data stored on virtual machine disk images","B Providing network security between virtual machines in the same host","C Managing and isolating virtual machines, controlling access to physical hardware resources","D Monitoring virtual machine processes for malicious behavior"], correct:2, explanation:"The hypervisor (VMM) creates and manages virtual machines, enforcing isolation between them by mediating access to physical resources (CPU, memory, I/O). Its security is critical since a compromised hypervisor threatens all hosted VMs." },
  { id:30430, domain:3, level:2, question:"What is VM escape and why is it a critical security concern?", options:["A An attacker breaking out of a virtual machine to access the hypervisor or other VMs","B A VM unexpectedly shutting down and freeing its resources to the host","C A VM migrating to another physical host without authorization","D A vulnerability allowing VMs to consume more resources than allocated"], correct:0, explanation:"VM escape is a critical vulnerability where malicious code in a guest VM breaks out of its isolation to execute on the hypervisor or access other VMs, potentially compromising the entire physical host and all its virtual machines." },
  { id:30431, domain:3, level:2, question:"What is a container security concern compared to virtual machines?", options:["A Containers are less portable than virtual machines","B Containers use more resources than equivalent virtual machines","C Containers cannot be monitored by security tools","D Containers share the host OS kernel, so a kernel vulnerability could affect all containers on the host"], correct:3, explanation:"Unlike VMs with separate kernels, containers share the host OS kernel. A kernel-level vulnerability exploited in one container could potentially escape to the host or other containers, creating a larger blast radius than VM-based isolation." },
  { id:30432, domain:3, level:2, question:"What is the purpose of secure boot?", options:["A Encrypting the hard drive before the operating system loads","B Authenticating users before the operating system initializes","C Preventing physical access attacks by locking the boot sequence","D Ensuring that only cryptographically signed and trusted software loads during the boot process"], correct:3, explanation:"Secure boot verifies the digital signatures of each piece of boot software (UEFI firmware, bootloader, OS kernel) against a trusted database, ensuring that only authorized, unmodified software runs during system startup." },
  { id:30433, domain:3, level:2, question:"What is data masking used for in development and testing environments?", options:["A Encrypting production data before storing it in backups","B Anonymizing audit logs before archiving them for long-term retention","C Hiding sensitive fields from unauthorized users in production applications","D Replacing sensitive data with realistic but fictitious values to protect privacy in non-production use"], correct:3, explanation:"Data masking (data obfuscation) replaces sensitive production data (SSNs, credit cards, medical records) with realistic but fake values for use in development and testing, preventing unauthorized exposure of real sensitive data." },
  { id:30434, domain:3, level:2, question:"What is a Faraday cage used for in physical security?", options:["A Preventing physical intrusion into sensitive equipment areas","B Providing a secure storage area for classified documents","C Creating an electromagnetic barrier that blocks wireless signals from entering or leaving","D Protecting electrical equipment from power surges and lightning"], correct:2, explanation:"A Faraday cage is an enclosure made of conductive material that blocks electromagnetic fields. In security, it prevents wireless signals (Wi-Fi, cellular, RFID) from entering or leaving a space, protecting against wireless eavesdropping or electronic surveillance." },
  { id:30435, domain:4, level:2, question:"What does egress filtering accomplish in network security?", options:["A Blocking unsolicited inbound traffic from reaching internal systems","B Inspecting and filtering outbound traffic to prevent data exfiltration and limit attack capabilities","C Monitoring all outbound connections for compliance reporting purposes","D Authenticating outbound connection requests from internal users"], correct:1, explanation:"Egress filtering controls outbound traffic from the internal network, preventing data exfiltration, blocking outbound connections to malicious IPs, and limiting the damage attackers can do from inside a compromised network." },
  { id:30436, domain:4, level:2, question:"What is a honeynet?", options:["A A collection of threat intelligence feeds from honeypot data globally","B A network monitoring system using baited lures for intrusion detection","C A deception technology for redirecting attackers from real systems","D A network of honeypot systems designed to attract and study attackers"], correct:3, explanation:"A honeynet is a network of honeypot systems designed to look like a real network to attract attackers. It provides a controlled environment to observe attacker behavior, tactics, and tools without risking production systems." },
  { id:30437, domain:4, level:2, question:"What is a SIEM's correlation rule primarily used for?", options:["A Encrypting log data before storage to protect sensitive information","B Identifying patterns across multiple events that indicate a security incident","C Automatically remediating detected threats without human intervention","D Filtering out low-priority events to reduce analyst workload"], correct:1, explanation:"SIEM correlation rules analyze sequences or combinations of events across multiple sources to identify patterns that individually might be innocuous but together indicate a security incident, like failed logins followed by a successful login from a different location." },
  { id:30438, domain:4, level:2, question:"What is a web application firewall (WAF) designed to protect against?", options:["A Network-layer DDoS attacks targeting server bandwidth","B Unauthorized access to network infrastructure devices","C Application-layer attacks such as SQL injection, XSS, and CSRF targeting web applications","D Malware propagation through email and file sharing"], correct:2, explanation:"WAFs inspect HTTP/HTTPS traffic to detect and block application-layer attacks (OWASP Top 10) targeting web applications, including SQL injection, cross-site scripting, CSRF, and other web-specific vulnerabilities." },
  { id:30439, domain:4, level:2, question:"What is the purpose of a security orchestration, automation, and response (SOAR) platform?", options:["A Replacing security analysts with automated systems","B Automating repetitive security tasks and coordinating incident response workflows","C Providing threat intelligence from external feeds automatically","D Monitoring cloud environments without manual configuration"], correct:1, explanation:"SOAR platforms automate repetitive security tasks (phishing analysis, IoC enrichment, account isolation), orchestrate tools across the security stack, and manage incident response workflows, allowing analysts to focus on complex investigations." },
  { id:30440, domain:4, level:2, question:"What does micro-segmentation accomplish that traditional VLANs cannot?", options:["A Enforcing granular east-west traffic controls between individual workloads in the same network segment","B Providing encryption between all network segments","C Replacing physical network hardware with software-defined controls","D Authenticating each network packet against a policy database"], correct:0, explanation:"Micro-segmentation applies granular security policies to individual workloads or applications (not just network segments), controlling east-west traffic between systems in the same VLAN and limiting lateral movement within a segment." },
  { id:30441, domain:5, level:2, question:"What is identity proofing?", options:["A Testing identity management systems for vulnerabilities","B Proving that two identity systems contain consistent information","C Verifying that a person claiming an identity is actually that person during account creation","D Auditing identity management processes for compliance certification"], correct:2, explanation:"Identity proofing verifies the real-world identity of a person before issuing them credentials. It may involve checking government IDs, knowledge-based questions, or in-person verification, ensuring accounts are issued to the right individuals." },
  { id:30442, domain:5, level:2, question:"What is a service account and what special security considerations apply?", options:["A A shared account used by multiple services with no special security requirements","B An account used by applications or services with non-expiring credentials requiring tight monitoring","C A temporary account created for specific service requests","D An external vendor account with limited access to internal systems"], correct:1, explanation:"Service accounts are used by applications and automated processes. They often have elevated privileges, non-expiring passwords, and are difficult to protect with MFA, requiring special controls like managed service accounts, regular audits, and PAM integration." },
  { id:30443, domain:5, level:2, question:"What does the 'principle of least privilege' require when a user changes job roles?", options:["A The user's previous access is kept temporarily in case their new role requires it","B Access reviews should be conducted annually regardless of role changes","C Previous role access should be revoked and only new role-appropriate access granted","D Management approval is required before any access change takes effect"], correct:2, explanation:"When roles change, least privilege requires promptly revoking old-role access and granting only new-role-required access. Keeping old access leads to privilege accumulation (access creep), violating least privilege principles." },
  { id:30444, domain:5, level:2, question:"What is a token-based authentication system?", options:["A A system requiring physical hardware tokens for all authentication","B A system using one-time passwords delivered via SMS","C A system where after initial authentication, an access token is issued to represent the authenticated session","D A biometric authentication system using behavioral tokens"], correct:2, explanation:"Token-based authentication issues an access token (e.g., JWT) after successful authentication. The token is presented for subsequent requests, eliminating the need to re-authenticate with credentials for each request." },
  { id:30445, domain:5, level:2, question:"What is the security risk of excessive privilege accumulation (privilege creep)?", options:["A Users become confused by having too many access options","B Privilege accumulation increases licensing costs for access management tools","C Excess privileges cause performance issues in directory services","D Users accumulate more permissions than needed over time, violating least privilege and increasing insider threat risk"], correct:3, explanation:"Privilege creep occurs when users accumulate permissions over time through role changes without revoking old access. This violates least privilege and increases risk by giving users far more access than their current job requires." },
  { id:30446, domain:5, level:2, question:"What is the purpose of an identity governance and administration (IGA) system?", options:["A Monitoring for unauthorized account activity in real time","B Managing the full identity lifecycle including provisioning, access reviews, and policy enforcement","C Providing authentication services for cloud applications","D Enforcing password policies across all connected systems"], correct:1, explanation:"IGA systems manage the complete identity lifecycle—account creation, role assignments, access certifications, segregation of duties enforcement, and deprovisioning—providing governance and audit capabilities for access management." },
  { id:30447, domain:5, level:2, question:"What type of access control model allows data owners to control access to their own resources?", options:["A Discretionary Access Control (DAC)","B Mandatory Access Control (MAC)","C Role-Based Access Control (RBAC)","D Rule-Based Access Control"], correct:0, explanation:"In DAC, data owners have discretion to grant or revoke access to their resources. File system ACLs in Windows and UNIX implement DAC, allowing file owners to set permissions independently." },
  { id:30448, domain:5, level:2, question:"What is the purpose of multi-factor authentication (MFA)?", options:["A To make the login process more difficult for all users","B To require proof of identity from multiple independent factor categories, increasing security","C To eliminate the need for passwords in enterprise environments","D To comply with specific regulatory requirements for authentication"], correct:1, explanation:"MFA requires users to present multiple authentication factors from different categories (knowledge, possession, inherence), so that compromising one factor (e.g., password) alone is insufficient to gain access." },
  { id:30449, domain:5, level:2, question:"What is password spraying and how does it differ from brute force?", options:["A Password spraying tries many passwords against one account; brute force tries one password against many","B Password spraying tries a few common passwords against many accounts to evade lockout thresholds","C Password spraying uses dictionary attacks; brute force uses purely random combinations","D Password spraying targets privileged accounts; brute force targets all account types"], correct:1, explanation:"Password spraying tries a few commonly used passwords against a large number of accounts, staying below lockout thresholds. Traditional brute force exhausts all combinations against a single target account, typically triggering lockout." },
  { id:30450, domain:5, level:2, question:"What is an entitlement review and why is it important for security compliance?", options:["A A periodic review of user access rights to verify they are still appropriate and necessary","B A technical scan of systems to discover unauthorized software installations","C An audit of authentication logs to detect unauthorized login attempts","D A review of system vulnerabilities to prioritize remediation efforts"], correct:0, explanation:"Entitlement reviews (access certifications) have managers or data owners periodically confirm that user access rights remain appropriate, detecting access creep, orphaned accounts, and excessive permissions to maintain least privilege." }
];
